import { IMessageComposer } from '@nitrots/nitro-renderer';

// action: 1=HIT, 2=STAND, 3=DOUBLE (mirror on server)
export class BlackJackActionComposer implements IMessageComposer<unknown[]> {
    constructor(private _tableId: number, private _action: 1 | 2 | 3) {}
    public getMessageArray() {
        return [this._tableId, this._action];
    }
    public dispose(): void {}
    public get disposed(): boolean {
        return false;
    }
}
